    tip_keys = list(TIPS.keys())

    if self.tip_weights is None:
        return self.rng.choice(tip_keys)

    clamped_weights = [max(0.0, self.tip_weights.get(key, 1.0)) for key in tip_keys]
    total_weight = sum(clamped_weights)

    if total_weight == 0:
        return self.rng.choice(tip_keys)

